import { useState, useEffect } from "react";
import "./ViewByRole.css";

export default function ViewByRole() {
  const [roles, setRoles] = useState([]);
  const [employees, setEmployees] = useState([]);
  const [selectedRole, setSelectedRole] = useState("");

  /* =========================
        LOAD DATA
     ========================= */
  useEffect(() => {
    const storedRoles =
      JSON.parse(localStorage.getItem("designations")) || [];
    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];

    setRoles(storedRoles);
    setEmployees(storedEmployees);
  }, []);

  /* =========================
        FILTER EMPLOYEES
     ========================= */
  const filteredEmployees = selectedRole
    ? employees.filter(
        (emp) =>
          emp.designation &&
          emp.designation.toLowerCase() ===
            selectedRole.toLowerCase()
      )
    : [];

  return (
    <div className="view-by-role-page">
      <h2>View Employees By Designation</h2>

      {/* ================= SELECT ================= */}
      <select
        className="view-by-role-select"
        value={selectedRole}
        onChange={(e) => setSelectedRole(e.target.value)}
      >
        <option value="">Select Designation</option>
        {roles.map((r) => (
          <option key={r.id} value={r.title}>
            {r.title}
          </option>
        ))}
      </select>

      {/* ================= TABLE ================= */}
      <div className="view-by-role-table-card">
        <table className="view-by-role-table">
          <thead>
            <tr>
              <th>S.No</th>
              <th>Employee Name</th>
              <th>Email</th>
              <th>Department</th>
              <th>Designation</th>
            </tr>
          </thead>

          <tbody>
            {selectedRole === "" ? (
              <tr>
                <td colSpan="5" className="no-data">
                  Please select a designation
                </td>
              </tr>
            ) : filteredEmployees.length === 0 ? (
              <tr>
                <td colSpan="5" className="no-data">
                  No employees found
                </td>
              </tr>
            ) : (
              filteredEmployees.map((emp, index) => (
                <tr key={emp.id}>
                  <td>{index + 1}</td>
                  <td>{emp.name}</td>
                  <td>{emp.email}</td>
                  <td>{emp.department}</td>
                  <td>{emp.designation}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
